export const getAiEnhanceNotesUrl = () => {




  return `/api/ai/enhance-notes`
}

/**
 * @summary AI enhance or improve notes
 */
export const aiEnhanceNotes = async (aiEnhanceNotesRequest: AiEnhanceNotesRequest, options?: RequestInit): Promise<AiEnhanceNotesResult> => {

  return customFetch<AiEnhanceNotesResult>(getAiEnhanceNotesUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      aiEnhanceNotesRequest,)
  }
);}




